  }
}];

const cbQuery = $input.first().json.callback_query;
const data = cbQuery.data; // 'lang_FR' or 'lang_EN'
const lang = data.replace('lang_', ''); // 'FR' or 'EN'
const chatId = cbQuery.message.chat.id;
const telegramId = cbQuery.from.id;
const firstName = cbQuery.from.first_name || '';
const callbackId = cbQuery.id;

return [{
  json: {
    chat_id: chatId,
    telegram_id: telegramId,
    first_name: firstName,
    selected_language: lang,
    callback_query_id: callbackId,
    is_fr: lang === 'FR'
  }
}];

const msg = $input.first().json.message;
const doc = msg.document;
const chatId = msg.chat.id;
const telegramId = msg.from.id;
const fileSizeMB = doc.file_size / (1024 * 1024);
const MAX_SIZE_MB = 15;

return [{
  json: {
    chat_id: chatId,
    telegram_id: telegramId,
    file_id: doc.file_id,
    file_name: doc.file_name || 'fichier_sans_nom',
    file_size: doc.file_size,
    file_size_mb: doc.file_size ? (doc.file_size / (1024*1024)).toFixed(2) : '< 1',  // ← ici
