// NODE: Detect File Type — remplacer tout le contenu par ce code

const fileInfo = $('Prepare File Info').item.json;
const fileName = (fileInfo.file_name || '').toLowerCase();
const mimeType = (fileInfo.mime_type || '').toLowerCase();

let detectedType = 'unknown';

if (mimeType.includes('pdf') || fileName.endsWith('.pdf')) {
  detectedType = 'pdf';
} else if (mimeType.includes('excel') || mimeType.includes('spreadsheet') ||
           fileName.match(/\.(xlsx?|xlsm)$/i)) {
  detectedType = 'excel';
} else if (mimeType.includes('word') || mimeType.includes('document') ||
           fileName.match(/\.docx?$/i)) {
  detectedType = 'word';
} else if (mimeType.includes('csv') || fileName.endsWith('.csv')) {
  detectedType = 'csv';
}

const binaryData = $input.first().binary;
const fileKey = binaryData ? Object.keys(binaryData)[0] : null;

let fileBuffer = '';
let fileSizeBytes = fileInfo.file_size || 0;

if (fileKey) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, fileKey);
  fileBuffer = buffer.toString('base64');
  fileSizeBytes = buffer.length;
}

return [{
  json: {
    ...fileInfo,
    detectedType,
    isSupported: ['pdf', 'excel', 'word', 'csv'].includes(detectedType),
    fileBuffer,
    file_size: fileSizeBytes
  }
}];

const pdfParse = require('pdf-parse');
const fileBuffer = Buffer.from($input.first().json.fileBuffer, 'base64');

try {
  const data = await pdfParse(fileBuffer, { max: 0 });
  const maxChars = 12000;
  const text = data.text;
  return [{
    json: {
      success: true,
      content_type: 'document',
      text: text.length > maxChars ? text.substring(0, maxChars) + '\n...[tronqué]' : text,
      num_pages: data.numpages,
      is_truncated: text.length > maxChars,
      char_count: text.length,
      preview_text: `${data.numpages} page(s), ${text.length} caractères`,
      ...$input.first().json
    }
  }];
} catch(e) {
  return [{ json: { success: false, error: e.message, ...$input.first().json } }];
}

const XLSX = require('xlsx');
const fileBuffer = Buffer.from($input.first().json.fileBuffer, 'base64');

try {
  const workbook = XLSX.read(fileBuffer, { type: 'buffer' });
  const firstSheet = workbook.Sheets[workbook.SheetNames[0]];
  const jsonData = XLSX.utils.sheet_to_json(firstSheet, { header: 1, defval: null, blankrows: false });

  const headers = jsonData[0] || [];
  const rows = jsonData.slice(1, 101).map(row => {
    const obj = {};
    headers.forEach((h, i) => { obj[h] = row[i]; });
    return obj;
  });

  const preview = `${workbook.SheetNames.length} feuille(s), ${jsonData.length - 1} lignes, ${headers.length} colonnes\nColonnes : ${headers.slice(0, 6).join(', ')}${headers.length > 6 ? '...' : ''}`;

  return [{
    json: {
      success: true,
      content_type: 'data',
      columns: headers,
      data: rows,
      total_rows: jsonData.length - 1,
      sheet_names: workbook.SheetNames,
      preview_text: preview,
      is_sample: jsonData.length > 102,
      ...$input.first().json
    }
  }];
} catch(e) {
  return [{ json: { success: false, error: e.message, ...$input.first().json } }];
}

const mammoth = require('mammoth');
const fileBuffer = Buffer.from($input.first().json.fileBuffer, 'base64');

try {
  const result = await mammoth.extractRawText({ buffer: fileBuffer });
  const maxChars = 12000;
  const text = result.value;
  return [{
    json: {
      success: true,
      content_type: 'document',
      text: text.length > maxChars ? text.substring(0, maxChars) + '\n...[tronqué]' : text,
      is_truncated: text.length > maxChars,
      char_count: text.length,
      preview_text: `Document Word, ${text.length} caractères`,
      ...$input.first().json
    }
  }];
} catch(e) {
  return [{ json: { success: false, error: e.message, ...$input.first().json } }];
}

const fileBuffer = Buffer.from($input.first().json.fileBuffer, 'base64');
const csvContent = fileBuffer.toString('utf-8');

const lines = csvContent.split('\n').filter(l => l.trim());
const firstLine = lines[0] || '';
let delimiter = ',';
if (firstLine.includes(';') && !firstLine.includes(',')) delimiter = ';';
else if (firstLine.includes('\t')) delimiter = '\t';

const parseLine = (line) => {
  const res = []; let cur = ''; let inQ = false;
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"') { if (inQ && line[i+1] === '"') { cur += '"'; i++; } else { inQ = !inQ; } }
    else if (c === delimiter && !inQ) { res.push(cur.trim()); cur = ''; }
    else cur += c;
  }
  res.push(cur.trim());
  return res;
};

const headers = parseLine(lines[0]);
const rows = lines.slice(1, 101).map(l => {
  const vals = parseLine(l);
  const row = {};
  headers.forEach((h, i) => { row[h] = vals[i] || null; });
  return row;
});

const preview = `${lines.length - 1} lignes, ${headers.length} colonnes\nColonnes : ${headers.slice(0, 6).join(', ')}${headers.length > 6 ? '...' : ''}`;

return [{
  json: {
    success: true,
    content_type: 'data',
    columns: headers,
    data: rows,
    total_rows: lines.length - 1,
    delimiter,
    preview_text: preview,
    is_sample: lines.length > 102,
    ...$input.first().json
  }
}];

const d = $input.first().json;
const sessionRow = d || {};
const fileData = $('Prepare Session Data').item.json;
const userRow = $('Get User Info').item.json || {};

const lang = userRow.language || 'FR';
const sessionId = sessionRow.id || 0;
const chatId = fileData.p1;           // ← p1 = chat_id
const fileName = fileData.p2 || 'fichier';   // ← p2 = file_name
const fileType = fileData.p3 || 'unknown';   // ← p3 = detectedType
const fileSizeBytes = parseInt(fileData.p4) || 0;
const fileSizeMb = (fileSizeBytes / (1024 * 1024)).toFixed(2);
const previewText = fileData.p5 || '';       // ← p5 = preview

// Labels selon la langue
const isFR = lang === 'FR';
const typeLabels = {
  csv: 'Tableau CSV',
  excel: 'Fichier Excel',
  pdf: 'Document PDF',
  word: 'Document Word',
  unknown: 'Fichier'
};
const typeLabel = typeLabels[fileType] || 'Fichier';

const msgFR = `📋 *Aperçu du fichier*\n\n📄 *${fileName}*\n🔹 Type : ${typeLabel}\n📦 Taille : ${fileSizeMb} MB\n🆔 Session : \`${sessionId}\`\n\n*Extrait :*\n\`\`\`\n${previewText.substring(0, 300)}\n\`\`\`\n\n*Choisissez le type d'analyse :*`;

const msgEN = `📋 *File Preview*\n\n📄 *${fileName}*\n🔹 Type: ${typeLabel}\n📦 Size: ${fileSizeMb} MB\n🆔 Session: \`${sessionId}\`\n\n*Extract:*\n\`\`\`\n${previewText.substring(0, 300)}\n\`\`\`\n\n*Choose analysis type:*`;

return [{
  json: {
    chat_id: chatId,
    session_id: sessionId,
    message_text: isFR ? msgFR : msgEN,
    auto_button_fr: isFR ? '⚡ Analyse Automatique' : '⚡ Auto Analysis',
    auto_button_en: isFR ? '🎯 Analyse Personnalisée' : '🎯 Custom Analysis',
    callback_auto: `auto_${sessionId}`,
    callback_custom: `custom_${sessionId}`,
    lang: lang
  }
}];

// NODE: Prepare Session Data — remplacer tout le contenu par ce code

const d = $input.first().json;
const extracted = {
  columns: d.columns || null,
  data: (d.data || []).slice(0, 50),
  text: d.text || null,
  content_type: d.content_type || null
};

return [{json: {
  p1: String(d.chat_id),
  p2: d.file_name || 'fichier',
  p3: d.detectedType || 'unknown',
  p4: String(d.file_size || 0),
  p5: (d.preview_text || 'Extrait').substring(0, 200).replace(/[,\n\r]/g, ' ').trim(),
  p6: Buffer.from(JSON.stringify(extracted)).toString('base64'),
  p7: String(d.telegram_id)
}}];

// Gère les callbacks auto_N et custom_N
// Pattern §8 : .replace(/^=/, '') obligatoire
const raw = $input.first().json.callback_query.data.replace(/^=/, '');

if (!raw.startsWith('auto_') && !raw.startsWith('custom_')) {
  return [];
}

const parts = raw.split('_');
const sessionId = parseInt(parts[parts.length - 1]);
const cbQuery = $input.first().json.callback_query;

return [{
  json: {
    is_auto:     raw.startsWith('auto_'),
    analysis_type: raw.startsWith('auto_') ? 'auto' : 'custom',
    session_id:  sessionId,
    chat_id:     cbQuery.message.chat.id,
    telegram_id: cbQuery.from.id,
    message_id:  cbQuery.message.message_id,
    language:    cbQuery.from.language_code || 'fr'
  }
}];

const d = $input.first().json;
const r = d.analysis;
const isFR = d.language === 'FR';
let message = '';

if (d.content_type === 'data') {
  const header = isFR ? '📊 *RAPPORT D\'ANALYSE*' : '📊 *ANALYSIS REPORT*';
  const overview = r.overview || {};
  const findings = (r.key_findings || []).map((f, i) => (i+1) + '. ' + f).join('\n');
  const recos = (r.recommendations || []).map(rec => '• ' + rec).join('\n');

  const rowsLabel   = isFR ? ' lignes · '   : ' rows · ';
  const colsLabel   = isFR ? ' colonnes · Qualité : ' : ' columns · Quality: ';

  message = header
    + '\n📄 *' + d.file_name + '*\n🤖 Grok AI'
    + '\n\n📋 *' + (isFR ? "Vue d'ensemble" : 'Overview') + '*\n'
    + (overview.rows || '?') + rowsLabel
    + (overview.columns || '?') + colsLabel
    + (overview.data_quality || '?')
    + '\n\n✨ *' + (isFR ? 'Résumé Exécutif' : 'Executive Summary') + '*\n' + (r.executive_summary || '')
    + '\n\n🔑 *' + (isFR ? 'Points Clés' : 'Key Findings') + '*\n' + findings
    + '\n\n💡 *' + (isFR ? 'Recommandations' : 'Recommendations') + '*\n' + recos
    + '\n\n⏱ _' + d.response_time_ms + 'ms · Grok AI_';

} else {
  const header = isFR ? '📄 *ANALYSE DU DOCUMENT*' : '📄 *DOCUMENT ANALYSIS*';
  const points = (r.key_points || []).map((p, i) => (i+1) + '. ' + p).join('\n');
  const insights = (r.insights || []).map(ins => '💡 ' + ins).join('\n');
  const qualityLabel = isFR ? ' · Qualité : ' : ' · Quality: ';

  message = header
    + '\n📄 *' + d.file_name + '*\n🤖 Grok AI'
    + '\n\n✨ *' + (isFR ? 'Résumé Exécutif' : 'Executive Summary') + '*\n' + (r.executive_summary || '')
    + '\n\n🔑 *' + (isFR ? 'Points Clés' : 'Key Points') + '*\n' + points
    + '\n\n🔍 *Insights*\n' + insights
    + '\n\n🎯 *' + (isFR ? 'Public Cible' : 'Target Audience') + '*\n'
    + (r.target_audience || (isFR ? 'Non déterminé' : 'Not determined'))
    + qualityLabel + (r.quality_score || '?')
    + '\n\n⏱ _' + d.response_time_ms + 'ms_';
}

if (message.length > 4096) message = message.substring(0, 4090) + '..._';

return [{
  json: {
    ...d,
    report_message: message,
    charts: r.charts || []
  }
}];

const d = $input.first().json;
const charts = d.charts || [];
const extractedData = d.extracted_data;

if (d.content_type !== 'data' || !charts.length || !extractedData || !extractedData.data) {
  return [{ json: { ...d, chart_urls: [], charts_count: 0 } }];
}

const rows = extractedData.data || [];
const cols = extractedData.columns || [];
const chartUrls = [];

for (const chart of charts.slice(0, 3)) {
  const type = chart.type || 'bar';
  const xCol = chart.x || cols[0];
  const yCol = chart.y || cols[1];
  if (!xCol || !yCol) continue;
  const xValues = rows.map(r => r[xCol]).filter(v => v != null).slice(0, 20);
  const yValues = rows.map(r => parseFloat(r[yCol])).filter(v => !isNaN(v)).slice(0, 20);
  if (!xValues.length || !yValues.length) continue;
  const chartConfig = {
    type: type,
    data: {
      labels: type !== 'scatter' ? xValues.map(String) : undefined,
      datasets: [{
        label: yCol,
        data: type === 'scatter' ? xValues.map((x, i) => ({ x, y: yValues[i] })) : yValues,
        backgroundColor: 'rgba(99, 102, 241, 0.5)',
        borderColor: 'rgba(99, 102, 241, 1)',
        borderWidth: 2,
        fill: false,
        tension: 0.3
      }]
    },
    options: {
      plugins: { title: { display: true, text: chart.title || (yCol + ' par ' + xCol) } }
    }
  };
  const encodedConfig = encodeURIComponent(JSON.stringify(chartConfig));
  chartUrls.push({
    url: 'https://quickchart.io/chart?c=' + encodedConfig + '&w=700&h=400&bkg=white',
    title: chart.title || '',
    insight: chart.insight || ''
  });
}

return [{ json: { ...d, chart_urls: chartUrls, charts_count: chartUrls.length } }];

const d = $input.first().json;

// Récupération directe depuis Prepare Agent Input (bypass du chain)
const agentInput = $('Prepare Agent Input').first().json;
const sessionId = agentInput.session_id;
const chatId = agentInput.chat_id;
const language = agentInput.language;

// Debug : vérifie dans la console n8n
console.log('session_id:', sessionId);
console.log('agentInput keys:', Object.keys(agentInput));

return [{
  json: {
    p1: d.llm_used || 'grok',
    p2: Buffer.from(JSON.stringify(d.analysis || {})).toString('base64'),
    p3: String(Math.round(d.response_time_ms || 0)),
    p4: String(sessionId),
    chat_id: chatId,
    language: language,
    session_id: sessionId
  }
}];

// Chemin optionnel : split les graphiques pour envoi individuel
// Pattern CLAUDE.md : ce node peut retourner [] sans bloquer Update Session / Send Final Menu
const d = $input.first().json;
const charts = d.chart_urls || [];

if (!charts.length) {
  return [];
}

return charts.map(chart => ({
  json: {
    chat_id: d.chat_id,
    photo_url: chart.url,
    caption: '📊 ' + chart.title + '\n_' + chart.insight + '_'
  }
}));

const row = $input.first().json;
const callbackData = $('Extract Callback Data').item.json;

// Parse extracted_data (stocké en JSONB, retourné comme text)
let extractedData = {};
try {
  const raw = row.extracted_data_raw || '{}';
  extractedData = typeof raw === 'object' ? raw : JSON.parse(raw);
} catch(e) {
  extractedData = { content_type: 'document', text: '' };
}

const lang = row.language || 'FR';
const fileName = row.file_name || 'fichier';
const fileType = row.file_type || 'unknown';
const contentType = extractedData.content_type || 'document';

let userPrompt = '';

if (contentType === 'data') {
  const dataStr = JSON.stringify({
    columns: extractedData.columns || [],
    sample_data: (extractedData.data || []).slice(0, 50),
    total_rows: extractedData.total_rows || 0
  });
  userPrompt = 'Analyse ce dataset et produis un rapport complet.\n\nDONNÉES :\n' + dataStr + '\n\nFICHIER : ' + fileName + ' (' + fileType.toUpperCase() + ')\nLANGUE : ' + (lang === 'FR' ? 'Français' : 'English') + '\n\nFORMAT REQUIS (JSON pur, sans markdown, sans texte avant/après) :\n{\n  "executive_summary": "3-4 phrases synthétiques",\n  "overview": {"rows": N, "columns": N, "data_quality": "X/10"},\n  "key_findings": ["finding 1", "finding 2", "finding 3"],\n  "detections": {"trends": [], "anomalies": [], "correlations": []},\n  "charts": [{"type": "bar", "title": "titre", "x": "colonne_x", "y": "colonne_y", "insight": "explication"}],\n  "recommendations": ["reco 1", "reco 2"]\n}';
} else {
  const text = (extractedData.text || '').substring(0, 8000);
  userPrompt = 'Analyse ce document et produis un rapport structuré.\n\nDOCUMENT :\n' + text + '\n\nFICHIER : ' + fileName + ' (' + fileType.toUpperCase() + ')\nLANGUE : ' + (lang === 'FR' ? 'Français' : 'English') + '\n\nFORMAT REQUIS (JSON pur, sans markdown, sans texte avant/après) :\n{\n  "executive_summary": "3-4 phrases",\n  "key_points": ["point 1", "point 2", "point 3"],\n  "insights": ["insight 1", "insight 2"],\n  "document_type": "type détecté",\n  "target_audience": "public cible",\n  "quality_score": "X/10",\n  "recommendations": ["reco 1"]\n}';
}

return [{
  json: {
    session_id: row.id || callbackData.session_id,
    chat_id: row.chat_id || callbackData.chat_id,
    telegram_id: row.telegram_id || callbackData.telegram_id,
    language: lang,
    file_name: fileName,
    file_type: fileType,
    content_type: contentType,
    extracted_data: extractedData,
    user_prompt: userPrompt,
    start_time: Date.now()
  }
}];

const chainOutput = $input.first().json;
const metadata = $('Prepare Agent Input').first().json;

// Basic LLM Chain retourne { text: "..." }
// On garde les fallbacks au cas où
// n8n récent : Basic LLM Chain retourne { response: { text: "..." } }
// n8n ancien : { text: "..." }
// Fallbacks pour Agent / HTTP / autres
const rawOutput = (chainOutput.response && chainOutput.response.text)
               || chainOutput.text
               || chainOutput.output
               || (typeof chainOutput.response === 'string' ? chainOutput.response : '')
               || (chainOutput.choices && chainOutput.choices[0] && chainOutput.choices[0].message && chainOutput.choices[0].message.content)
               || '';

console.log('=== DEBUG Basic LLM Chain output ===');
console.log('keys:', JSON.stringify(Object.keys(chainOutput)));
console.log('rawOutput length:', rawOutput.length);
console.log('rawOutput preview:', rawOutput.substring(0, 200));

const responseTimeMs = Date.now() - (metadata.start_time || Date.now());
const tokensUsed = chainOutput.tokenUsage
  ? (chainOutput.tokenUsage.totalTokens || 0)
  : 0;

let analysis = null;
try {
  let clean = rawOutput.trim();
  if (clean.startsWith('```')) {
    clean = clean.replace(/^```json?\n?/, '').replace(/\n?```$/, '');
  }
  const jsonStart = clean.indexOf('{');
  const jsonEnd = clean.lastIndexOf('}');
  if (jsonStart !== -1 && jsonEnd !== -1) {
    clean = clean.substring(jsonStart, jsonEnd + 1);
  }
  analysis = JSON.parse(clean);
} catch(e) {
  console.log('Parse error:', e.message);
  console.log('Failed on:', rawOutput.substring(0, 300));
  analysis = {
    executive_summary: rawOutput.substring(0, 500) || 'Analyse non disponible',
    key_findings: ['Erreur parsing JSON — vérifier le modèle IA'],
    parse_error: true
  };
}

return [{
  json: {
    ...metadata,
    analysis: analysis,
    response_time_ms: responseTimeMs,
    tokens_used: tokensUsed,
    llm_used: 'ollama-kimi',
    parse_success: !analysis.parse_error
  }
}];

const msg = $input.first().json.message || $input.first().json;
const chatId = msg.chat?.id || msg.chat_id;
const text = (msg.text || '').trim();
const msgId = msg.message_id;
const firstName = msg.from?.first_name || 'Utilisateur';
return [{ json: { chat_id: chatId, text, message_id: msgId, first_name: firstName, is_cancel: text.toLowerCase() === '/cancel' } }];

const data = $input.first().json;
const text = data.user_text || '';
const lang = data.language;
const len = text.length;
let error_msg = null;
if (len < 3) error_msg = lang === 'ENG' ? '⚠️ Response too short. Please enter at least 3 characters.' : '⚠️ Réponse trop courte. Veuillez entrer au moins 3 caractères.';
if (len > 500) error_msg = lang === 'ENG' ? '⚠️ Response too long (max 500 characters). Please rephrase.' : '⚠️ Réponse trop longue (max 500 caractères). Veuillez reformuler.';
return [{ json: { ...data, is_valid: error_msg === null, error_msg } }];

const session = $input.first().json;
const answers = session.custom_answers || {};
const lang = session.language || 'FR';
const fileType = (session.file_type || 'unknown').toUpperCase();
const fileName = session.file_name || 'fichier';
const preview = session.extracted_preview || '';

let fileData = '';
try {
  const rawData = session.extracted_data;
  if (rawData && typeof rawData === 'object') {
    fileData = JSON.stringify(rawData).substring(0, 8000);
  } else if (typeof rawData === 'string') {
    fileData = rawData.substring(0, 8000);
  }
} catch(e) {
  fileData = preview.substring(0, 4000);
}
if (!fileData) fileData = preview.substring(0, 4000);

const q1 = answers.q1 || (lang === 'ENG' ? 'Not specified' : 'Non précisé');
const q2 = answers.q2 || (lang === 'ENG' ? 'All available' : 'Toutes disponibles');
const q3 = answers.q3 || (lang === 'ENG' ? 'No specific filter' : 'Aucun filtre');
const q4 = answers.q4 || (lang === 'ENG' ? 'Complete analysis' : 'Analyse complète');
const q5 = answers.q5 || (lang === 'ENG' ? 'General' : 'Général');

let prompt;
if (lang === 'ENG') {
  prompt = 'Analyze this ' + fileType + ' file: ' + fileName + '\n\n'
    + 'USER REQUIREMENTS:\n'
    + '1. Main goal: ' + q1 + '\n'
    + '2. Focus columns/sections: ' + q2 + '\n'
    + '3. Time period or filter: ' + q3 + '\n'
    + '4. Output type: ' + q4 + '\n'
